INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("フリーマーケットを訪れたジータが出会ったのは\n城をこっそり抜け出していたペコリーヌだった。", 91002, 20063115, "ペコリーヌとの出会い", "青空の下で謁見", 10118, 7, 2, 2834, 1, 40, "フリーマーケット会場", 0, 5118061, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータたちがフリーマーケットを巡っていると\n露店を出していたマホに声をかけられる。", 91002, 20063115, "マホとの出会い", "未来の騎空団\nマスコット？", 10118, 7, 2, 2835, 1, 40, "フリーマーケット会場", 0, 5118062, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータが騎空団への依頼を確認していると、\n高笑いをしながらアキノが現れる。", 91002, 20063115, "アキノとの出会い", "お嬢さまからの\n緊急依頼", 10118, 7, 2, 2837, 1, 40, "ランドソル市街地", 0, 5118063, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ジータたちは、フリーマーケット会場で\n少し困った様子のジュンを見かける。", 91002, 20063115, "ジュンとの出会い", "黄金色の悩みごと", 10118, 18, 2, 4108402, 1, 40, "フリーマーケット会場", 0, 5118064, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("フリーマーケットの隅で開かれる格闘大会──\nそこにはカオリもいて……？", 91002, 20063115, "カオリとの出会い", "白熱！　格闘大会！", 10118, 18, 2, 4107402, 1, 40, "フリーマーケット会場", 0, 5118065, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("太鼓祭を控えるオーエド町──\nジータは、困った様子のニノンと出会う。", 91002, 20063115, "ニノンとの出会い", "祭り太鼓はオーエドの華", 10118, 16, 2, 9000227, 1, 40, "オーエド町", 1, 5118066, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラはイベントに出演中のスズナを見かける。\nしかし、スズナはどこか困っているようで……？", 91002, 20063115, "スズナとの出会い", "人気者は遅れて\nやってくる", 10118, 19, 3, 2101181, 1, 40, "フリーマーケット会場", 0, 5118067, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラたちが街を散策していると、通りかかった\nナナカが興奮した様子で近づいてきて……？", 91002, 20063115, "ナナカとの出会い", "巫女・ミーツ・魔法少女", 10118, 18, 3, 4109402, 1, 40, "ランドソル市街地", 0, 5118068, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ネズ耳をなくしてしまい絶望するビカラ。同じ頃\nキャルとコッコロは落とし物を拾っており……", 91002, 20063115, "キャル＆コッコロとの出会い", "ネズ耳は二度なくなる", 10118, 18, 3, 4305402, 1, 40, "フリーマーケット会場", 0, 5118069, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("街外れでひと休みをしていたビカラたちは、\nすっかりゴキゲンな様子のユカリと出会う。", 91002, 20063115, "ユカリとの出会い", "この出会いにカンパイ！", 10118, 18, 3, 4101402, 1, 40, "ランドソル市街地", 0, 5118070, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラは、人混みに怯えるアオイを心配し、\n陽気に声をかけるも……", 91002, 20063115, "アオイとの出会い", "陰陽アンサンブル", 10118, 18, 3, 4106402, 1, 40, "ランドソル市街地", 0, 5118071, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES ("ビカラがフリーマーケット会場を歩いていると\n占いをしていたシノブに声をかけられる。", 91002, 20063115, "シノブとの出会い", "運試し十番勝負！", 10118, 7, 3, 2836, 1, 40, "フリーマーケット会場", 1, 5118072, 8);
INSERT INTO `v1_a6d7f06e43f9ed9bc445d32c3eccff482e38c59efec2bb17fb4e725a301cb3a9` VALUES (0, 0, 20063115, "オープニング", "彼女たちの新たな日常", 10118, 0, 1, 0, 0, 0, 0, 0, 5118600, 0);
